Only FYI. Reordering of local and global sections isn't necessary in this case. Seems that global section have priority before local section.


root@tegra210:/usr/ports/multimedia/mplayer/work/mplayer-export-2018-12-24 # ld -v
LLD 7.0.1 (FreeBSD 349250-1300001) (compatible with GNU linkers)

root@tegra210:/usr/ports/multimedia/mplayer/work/mplayer-export-2018-12-24 # more binary.ver
MPLAYER_1 {
  # to support glibcs abhorrent backwards-compatibility hack
  global: _IO_stdin_used;
          __progname;
          environ;

  local: *;
};

root@tegra210:/usr/ports/multimedia/mplayer/work/mplayer-export-2018-12-24 # readelf -s ./mplayer | grep environ
   818: 0000000000500000     8 OBJECT  GLOBAL DEFAULT   24 environ@@MPLAYER_1 (2)
  7023: 0000000000500000     8 OBJECT  GLOBAL DEFAULT   24 environ

